import React, { useCallback, useEffect, useMemo, useState } from 'react';
import { LinErpListFilterBar, Select, Tabs, dispatchAppToast } from '@linm-soft-org/linm-web-common-components';
import { useAppDispatch } from '../../../store/hooks';
import { analyticsService } from '../../../services/analytics/analyticsService';
import { formatVnd, parseReportStt } from '../../../utils/formatters';
import { MONTH_OPTIONS, YEAR_OPTIONS } from '../../../utils/exportExcel';
import { getApiErrorMessage } from '../../../utils/getApiErrorMessage';
import reportStyles from '../../../styles/erpReportPage.module.css';
import type { B01Row, B02Row, B03Row } from '../../../services/analytics/models';
import { AnalyticsReportShell, ReportTableWrap } from '../../../components/report';

const TEST_ID = 'erp-bao-cao-tai-chinh';
const PAGE_ID = 'baocao-tai-chinh';

/** Left padding per indent level (px). */
const INDENT_PX = 24;

const BaoCaoTaiChinhPage: React.FC = () => {
  const dispatch = useAppDispatch();
  const now = new Date();
  const [month, setMonth] = useState(now.getMonth() + 1);
  const [year, setYear] = useState(now.getFullYear());
  const [tab, setTab] = useState<'b01' | 'b02' | 'b03'>('b01');
  const [b01, setB01] = useState<B01Row[]>([]);
  const [b02, setB02] = useState<B02Row[]>([]);
  const [b03, setB03] = useState<B03Row[]>([]);
  const [loading, setLoading] = useState(false);

  const handleLoad = useCallback(() => {
    setLoading(true);
    const p = { month, year };
    const req =
      tab === 'b01'
        ? analyticsService.getB01Dn(p)
        : tab === 'b02'
          ? analyticsService.getB02Dn(p)
          : analyticsService.getB03Dn({ year });
    req
      .then(d => {
        if (tab === 'b01') setB01(d as B01Row[]);
        else if (tab === 'b02') setB02(d as B02Row[]);
        else setB03(d as B03Row[]);
      })
      .catch(err =>
        dispatchAppToast(dispatch, {
          message: getApiErrorMessage(err, 'Lỗi'),
          type: 'error',
        }),
      )
      .finally(() => setLoading(false));
  }, [month, year, tab, dispatch]);

  // Auto-load on mount and on tab/month/year change
  useEffect(() => { handleLoad(); }, [handleLoad]);

  const rows = tab === 'b01' ? b01 : tab === 'b02' ? b02 : b03;
  const exportPath =
    tab === 'b01'
      ? '/reports/financial/b01-dn/export-excel'
      : tab === 'b02'
        ? '/reports/financial/b02-dn/export-excel'
        : '/reports/financial/b03-dn/export-excel';

  /** Render Chỉ tiêu cell with indent based on level */
  const renderIndicator = (name: string, code: string, indent?: number) => {
    const indentPx = indent ? indent * INDENT_PX : 0;
    const { stt, label } = parseReportStt(name);
    return (
      <>
        <td className={reportStyles.colStt}>{stt}</td>
        <td style={{ paddingLeft: `${16 + indentPx}px` }}>{label}</td>
        <td className={reportStyles.colStt}>{code}</td>
        <td className={reportStyles.colStt}>{''}</td>
      </>
    );
  };

  const listFilters = useMemo(
    () => (
      <LinErpListFilterBar
        testIdPrefix={TEST_ID}
        onDateChange={() => {}}
        onSearch={handleLoad}
        searchAriaLabel="Xem"
        loading={loading}
        leading={(
          <>
            {tab !== 'b03' && (
              <div data-testid={`${TEST_ID}-field-month`}>
                <Select label="Tháng" value={String(month)} onChange={e => setMonth(Number(e.target.value))} options={MONTH_OPTIONS} size="small" />
              </div>
            )}
            <div data-testid={`${TEST_ID}-field-year`}>
              <Select label="Năm" value={String(year)} onChange={e => setYear(Number(e.target.value))} options={YEAR_OPTIONS} size="small" />
            </div>
          </>
        )}
      />
    ),
    [month, year, tab, handleLoad, loading],
  );

  return (
    <AnalyticsReportShell
      testId={TEST_ID}
      pageId={PAGE_ID}
      title="Báo cáo tài chính"
      titleIconClass="fas fa-file-invoice-dollar"
      loading={loading}
      hasData={rows.length > 0}
      filters={listFilters}
      onLoad={handleLoad}
      exportPath={exportPath}
      exportParams={tab === 'b03' ? { year } : { month, year }}
      exportFilename={`BC-TC-${tab}.xlsx`}
      tabBar={(
        <Tabs
          tabs={[
            { id: 'b01', label: 'B01' },
            { id: 'b02', label: 'B02' },
            { id: 'b03', label: 'B03' },
          ]}
          activeTab={tab}
          onTabChange={id => setTab(id as 'b01' | 'b02' | 'b03')}
          variant="underline"
          className={reportStyles.reportCompactTabs}
        />
      )}
    >
      <ReportTableWrap testId={`${TEST_ID}-grid`}>
        <thead>
          <tr>
            <th className={reportStyles.colStt}>STT</th>
            <th>Chỉ tiêu</th>
            <th className={reportStyles.colStt}>Mã số</th>
            <th className={reportStyles.colStt}>Thuyết minh</th>
            {tab === 'b01' ? (
              <>
                <th className={reportStyles.colRight}>Số cuối năm</th>
                <th className={reportStyles.colRight}>Số đầu năm</th>
              </>
            ) : (
              <>
                <th className={reportStyles.colRight}>Kỳ này</th>
                <th className={reportStyles.colRight}>Kỳ trước</th>
              </>
            )}
          </tr>
        </thead>
        <tbody>
          {tab === 'b01'
            ? b01.map((r, i) => {
                let rowCls = '';
                if (r.isTotal) rowCls = reportStyles.rowTotal;
                else if (r.indent === 0 && !r.isTotal) rowCls = reportStyles.rowSectionHead;
                return (
                  <tr key={i} className={rowCls}>
                    {renderIndicator(r.name, r.code, r.indent)}
                    <td className={reportStyles.colRight}>{formatVnd(r.closingBalance)}</td>
                    <td className={reportStyles.colRight}>{formatVnd(r.openingBalance)}</td>
                  </tr>
                );
              })
            : tab === 'b02'
              ? b02.map((r, i) => {
                  let rowCls = '';
                  if (r.isTotal) rowCls = reportStyles.rowTotal;
                  else if (r.indent === 0 && !r.isTotal) rowCls = reportStyles.rowSectionHead;
                  return (
                    <tr key={i} className={rowCls}>
                      {renderIndicator(r.name, r.code, r.indent)}
                      <td className={reportStyles.colRight}>{formatVnd(r.currentAmount)}</td>
                      <td className={reportStyles.colRight}>{formatVnd(r.previousAmount)}</td>
                    </tr>
                  );
                })
              : b03.map((r, i) => {
                  let rowCls = '';
                  if (r.isTotal) rowCls = reportStyles.rowTotal;
                  else if (r.indent === 0 && !r.isTotal) rowCls = reportStyles.rowSectionHead;
                  return (
                    <tr key={i} className={rowCls}>
                      {renderIndicator(r.name, r.code, r.indent)}
                      <td className={reportStyles.colRight}>{formatVnd(r.currentAmount)}</td>
                      <td className={reportStyles.colRight}>{formatVnd(r.previousAmount)}</td>
                    </tr>
                  );
                })}
        </tbody>
      </ReportTableWrap>
    </AnalyticsReportShell>
  );
};

export default BaoCaoTaiChinhPage;
